public class UserInfo {

    private String guid;
    private String userId;
    private String firstName;
    private String lastName;
    private String corpId;
    private String roleId;
    private String roleFk;
    private boolean alreadyInDb = false;
    private boolean needsUpdating = false;

    public UserInfo() {
        //Random guid generated by default
        guid = UUID.randomUUID().toString().toLowerCase();
    }


    public String getGuid() {
        return guid;
    }

    public void setGuid(String guid) {
        this.guid = guid;
    }

    public String getUserId() {
        return userId;
    }

    public void setUserId(String userId) {
        this.userId = userId;
    }

    public String getFirstName() {
        return firstName;
    }

    public void setFirstName(String firstName) {
        this.firstName = firstName;
    }

    public String getLastName() {
        return lastName;
    }

    public void setLastName(String lastName) {
        this.lastName = lastName;
    }

    public String getCorpId() {
        return corpId;
    }

    public void setCorpId(String corpId) {
        this.corpId = corpId;
    }

    public String getRoleId() {
        return roleId;
    }

    public void setRoleId(String roleId) {
        this.roleId = roleId;
    }

    public String getRoleFk() {
        return roleFk;
    }

    public void setRoleFk(String roleFk) {
        this.roleFk = roleFk;
    }

    public boolean isAlreadyInDb() {
        return alreadyInDb;
    }

    public void setAlreadyInDb(boolean alreadyInDb) {
        this.alreadyInDb = alreadyInDb;
    }

    public boolean isNeedsUpdating() {
        return needsUpdating;
    }

    public void setNeedsUpdating(boolean needsUpdating) {
        this.needsUpdating = needsUpdating;
    }

}
